import Vue from "vue";
import App from "./App.vue";
import router from "./router";
import "./assets/css/main.css";
// import 'bootstrap/dist/css/bootstrap.min.css';

Vue.config.productionTip = false;

new Vue({
  router,
  render: function(h) {
    return h(App);
  },
  data: {
    isMobile: false
  },
  created: function() {
    this.isMobile = window.innerWidth <= 800;
  }
}).$mount("#app");
